```class Solution {
public:
    int latestTimeCatchTheBus(vector<int>& buses, vector<int>& passengers, int capacity) {
        sort(passengers.begin(), passengers.end());
        int lastBus = 0;
        for (int i = 0; i < passengers.size(); i++) {
            while (lastBus < buses.size() && buses[lastBus] <= passengers[i]) {
                lastBus++;
            }
            if (lastBus < buses.size()) {
                int departTime = buses[lastBus];
                int arriveTime = passengers[i];
                if (i < capacity) {
                    return departTime - 1;
                } else {
                    return min(departTime - 1, arriveTime);
                }
            }
        }
        return -1;
    }
};```
